            }
            if (!inductance) return 'N/A';

            const value = inductance.nominal || inductance.minimum;
            if (!value) return 'N/A';

            if (value >= 1e-3) return (value * 1e3).toFixed(2) + ' mH';
            if (value >= 1e-6) return (value * 1e6).toFixed(2) + ' µH';
            return (value * 1e9).toFixed(2) + ' nH';
        },
